const DIAS_ES = ['DOMINGO','LUNES','MARTES','MIÉRCOLES','JUEVES','VIERNES','SÁBADO'];
const hoy = DIAS_ES[new Date().getDay()];

const profesores = $('Obtener profesores').all().map(i => i.json);
const horarios = $('Obtener horarios').all().map(i => i.json);
const body = $('Recibir mensaje').item.json.body || $('Recibir mensaje').item.json;
const mensaje = body.message || '';
const historial = body.historial || [];

const FRANJAS = ['9:30-10:15','10:15-11:00','11:00-11:45','11:30-12:15','12:15-13:00','14:30-15:15','15:15-16:00'];

const nombreCompleto = p => `${p.nombre||''} ${p.apellidos||''}`.trim();
const guardiasDe = {};
const idDe = {};
profesores.forEach(p => {
  const n = nombreCompleto(p);
  guardiasDe[n] = p.guardiasRealizadas ?? 0;
  idDe[n] = p._id;
});
const todosProfes = profesores.map(nombreCompleto).filter(Boolean);

// Buscar nombre SOLO en mensajes del usuario, nunca del asistente
const mensajesUsuario = [mensaje, ...historial
  .filter(h => h.role === 'user')
  .map(h => h.content || '')
].join(' ').toLowerCase();

const profFalta =
  todosProfes.find(n => mensajesUsuario.includes(n.toLowerCase())) ||
  todosProfes.find(n => {
    const partes = n.toLowerCase().split(' ').filter(Boolean);
    return partes.filter(p => mensajesUsuario.includes(p)).length >= 2;
  }) ||
  todosProfes.find(n =>
    n.toLowerCase().split(' ').some(p => p.length > 3 && mensajesUsuario.includes(p))
  ) ||
  '';

// Franjas reales del profesor que falta HOY
let franjasDelFalta = '';
if (profFalta) {
  const clasesFalta = horarios.filter(h =>
    h.dia?.toUpperCase() === hoy &&
    h.profesor === profFalta
  );
  if (clasesFalta.length > 0) {
    franjasDelFalta = `=== CLASES DE ${profFalta.toUpperCase()} HOY (${hoy}) ===\n`;
    clasesFalta.forEach(h => {
      franjasDelFalta += `${h.hora} - ${h.asignatura} - Grupo ${h.grupo}\n`;
    });
    franjasDelFalta += '\n';
  } else {
    franjasDelFalta = `${profFalta} NO tiene clases hoy (${hoy}). No hay nada que cubrir.\n\n`;
  }
}

// Distribución inteligente
const asignaciones = {};
const guardiasHoy = {};
const ultimaFranja = {};

todosProfes.forEach(n => { guardiasHoy[n] = 0; ultimaFranja[n] = -99; });

const franjasACubrir = profFalta
  ? horarios
      .filter(h => h.dia?.toUpperCase() === hoy && h.profesor === profFalta)
      .map(h => h.hora)
  : [];

FRANJAS.forEach((franja, idx) => {
  if (profFalta && !franjasACubrir.includes(franja)) return;

  const ocupados = [...new Set(
    horarios
      .filter(h => h.dia?.toUpperCase() === hoy && h.hora === franja)
      .map(h => h.profesor)
      .filter(Boolean)
  )];

  const candidatos = todosProfes
    .filter(n =>
      !ocupados.includes(n) &&
      n !== profFalta &&
      guardiasHoy[n] < 2 &&
      (idx - ultimaFranja[n]) > 1
    )
    .sort((a,b) => (guardiasDe[a]??0) - (guardiasDe[b]??0));

  if (candidatos.length > 0) {
    const elegido = candidatos[0];
    asignaciones[franja] = elegido;
    guardiasHoy[elegido]++;
    ultimaFranja[elegido] = idx;
  } else {
    asignaciones[franja] = 'SIN CANDIDATO';
  }
});

// Contexto para Groq
let disponibilidadHoy = `=== DISTRIBUCIÓN PROPUESTA PARA HOY (${hoy}) ===\n`;
const franjasAsignadas = Object.keys(asignaciones);
if (franjasAsignadas.length > 0) {
  franjasAsignadas.forEach(franja => {
    const prof = asignaciones[franja];
    const g = guardiasDe[prof] ?? 0;
    disponibilidadHoy += `${franja} → ${prof} (${g} guardias acumuladas)\n`;
  });
} else {
  disponibilidadHoy += `No hay franjas que cubrir.\n`;
}

// SOLO los profesores realmente asignados (excluir al que falta)
const profesoresAsignados = [...new Set(
  Object.values(asignaciones)
    .filter(n => n && n !== 'SIN CANDIDATO' && n !== profFalta)
)];

const asignacionesConId = profesoresAsignados.map(nombre => ({
  profesor: nombre,
  id: idDe[nombre] || null,
  guardiasActuales: guardiasDe[nombre] ?? 0
})).filter(a => a.id);

return [{ json: {
  contexto: franjasDelFalta + disponibilidadHoy,
  mensaje,
  historial,
  hoy,
  asignaciones: asignacionesConId,
  profFalta
}}];

const respuesta = $json.choices[0].message.content;
const confirmado = respuesta.trim().toUpperCase().includes('CONFIRMADO');
const asignaciones = $('Preparar contexto').item.json.asignaciones || [];

const updates = [];

if (confirmado) {
  const conteo = {};
  asignaciones.forEach(a => {
    if (!a.id) return;
    if (!conteo[a.id]) {
      conteo[a.id] = {
        id: a.id,
        guardiasActuales: a.guardiasActuales,
      };
    }
  });

  Object.values(conteo).forEach(({ id, guardiasActuales }) => {
    updates.push({ id, guardiasRealizadas: guardiasActuales + 1 });
  });
}

return [{ json: {
  reply: respuesta,
  confirmado,
  updates
}}];
